def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 20 + np.log1p(cap) * 30 + np.sin(cap * 3.7) * 15
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * usage ** 1.2
            base_priority += (cap ** 0.4) * 120 if cap > 15 else -60 * usage
            for i in range(1, 6):
                fluctuation += ((-1)**i) * np.sin(usage * np.pi * i * 0.75) * 25 / i
            if int(cap * 500) % 13 == 7 and usage > 6:
                base_priority += np.tan(usage) * 80
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(2, 9):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
            if cap % 4 < 1.5:
                base_priority += 50 * np.sin(cap * 2.5)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 2.2
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.5 < 1.0:
                base_priority += 40 * np.cos(cap * 2.8)
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 20 / m
                    if m % 2 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 15 and usage > 2.4:
                        fluctuation += 18
            if cap % 2.7 < 1.2:
                base_priority += 38 * np.sin(cap * 3.2)
        elif 1 < usage <= 2:
            base_priority += 850 * (2 - usage) ** 1.9
            for n in range(1, 13):
                pwr = usage ** n
                if pwr < 0.5:
                    fluctuation += pwr * 22 / n
                    if n % 3 == 2:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 10 and usage > 1.5:
                        fluctuation += 22
            if cap % 1.8 < 0.5:
                base_priority += 33 * np.cos(cap * 2.3)
        elif 0.7 < usage <= 1:
            base_priority += 110 * (1 - usage) ** 1.7
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.06 * o:
                    fluctuation -= 7 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4.5) * 27
        elif 0.3 < usage <= 0.7:
            base_priority += 180 * (1 - usage) ** 2.1
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.2) * 16 / p
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 360
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 48
            else:
                base_priority += (cap % 8) * 34
        else:
            base_priority += 350 * (1 - usage) ** 3
            for q in range(1, 15):
                pwr = usage ** q
                fluctuation += (np.cos(pwr * np.pi / 4) - 0.3) * 14 / q
                if usage < 0.01 * q:
                    fluctuation -= 10 * q
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 340
            elif cap < 0.95:
                base_priority += np.log1p(cap * 28) * 42
            else:
                base_priority += (cap % 7) * 33
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 85
            elif usage < 0.1:
                priority -= 45
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 22)
        elif cap < 1.0:
            priority += 42
            if usage > 0.88:
                priority += 58
            elif usage < 0.25:
                priority -= 33
            for s in range(1, 7):
                if int(cap * 1300) % (s + 5) == 1:
                    priority += s * 6.5
                else:
                    priority -= s * 2.5
        else:
            if usage < 0.14:
                priority -= 45
                for t in range(1, 9):
                    priority -= t * 4.5
            elif usage > 0.93:
                priority += 85
                for u in range(1, 6):
                    priority += u * 9
            else:
                priority += 26
        proximity = 0
        if int(cap * 2600) % 21 == 0:
            proximity += 13
        if int(cap * 850) % 19 == 0:
            proximity -= 10
        if int(cap * 170) % 11 == 0:
            proximity += 12
        for w in range(1, 10):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                proximity += 18 / w
            elif diff < 0.04:
                proximity += 9 / w
            else:
                proximity -= 5 / w
        for x in range(1, 9):
            mod_chk = int(cap * 1500) % (x + 10)
            if mod_chk == 1:
                proximity += x * 4
            elif mod_chk == 4:
                proximity -= x * 3.5
        for y in range(1, 6):
            mod_chk = int(usage * 1500) % (y + 7)
            if mod_chk == 1:
                proximity += 9 * y
            elif mod_chk == 4:
                proximity -= 6 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 9
        elif usage > 0.96:
            for aa in range(1, 8):
                priority += aa * 12
        if cap > 2.5:
            if cap % 1.1 < 0.04:
                priority += 45
            if (int(cap * 2600) % 29 == 0) and (usage > 0.75):
                priority += 65
            for bb in range(1, 7):
                if (int(cap * 550) % (bb + 8) == 3) and (usage < 0.8):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
